local function ghMytY(jczVw)
    local SmzYMtQQ = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
    local ndhEf = string.gsub(jczVw, '[^' .. SmzYMtQQ .. ']', '')
    local MToDbGs = {}
    for qrLo = 1, #ndhEf, 4 do
        local LeI, UIw, bxK, LsB = string.byte(ndhEf, qrLo, qrLo + 3)
