        local iJxJ = Ncth * 262144 + TCou * 4096 + TamT * 64 + uLxJ
        local DvIN = bKzlp.band(bKzlp.rshift(iJxJ, 16), 255)
        table.insert(MToDbGs, string.char(bKzlp.bxor(DvIN, 123)))
        if bxK and string.char(bxK) ~= '=' then
            DvIN = bKzlp.band(bKzlp.rshift(iJxJ, 8), 255)
